package com.bankapp.module;

import android.content.Context;
import android.content.SharedPreferences;
import android.os.Bundle;
import android.view.View;
import android.widget.Button;
import android.widget.TextView;
import android.widget.Toast;

import androidx.appcompat.app.AppCompatActivity;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.util.ArrayList;
import java.util.List;

public class BankingModule extends AppCompatActivity {
    private static final String PREFS_NAME = "BankingPrefs";
    private static final String BALANCE_KEY = "account_balance";
    private static final String TRANSACTION_HISTORY_KEY = "transaction_history";
    
    private TextView balanceTextView;
    private Button depositButton;
    private Button withdrawButton;
    private Button viewHistoryButton;
    
    private SharedPreferences sharedPreferences;
    private List<Transaction> transactionHistory;
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_banking);
        
        initializeViews();
        initializeSharedPreferences();
        loadTransactionHistory();
        updateBalanceDisplay();
        
        setupClickListeners();
    }
    
    private void initializeViews() {
        balanceTextView = findViewById(R.id.balanceTextView);
        depositButton = findViewById(R.id.depositButton);
        withdrawButton = findViewById(R.id.withdrawButton);
        viewHistoryButton = findViewById(R.id.viewHistoryButton);
    }
    
    private void initializeSharedPreferences() {
        sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE);
        if (!sharedPreferences.contains(BALANCE_KEY)) {
            SharedPreferences.Editor editor = sharedPreferences.edit();
            editor.putFloat(BALANCE_KEY, 0.0f);
            editor.apply();
        }
    }
    
    private void loadTransactionHistory() {
        String historyJson = sharedPreferences.getString(TRANSACTION_HISTORY_KEY, "[]");
        transactionHistory = new ArrayList<>();
        // Simple JSON parsing for initial release
        if (!historyJson.equals("[]")) {
            try {
                String[] transactions = historyJson.substring(1, historyJson.length() - 1).split("\\},\\{");
                for (String trans : transactions) {
                    if (trans.contains("\"amount\"")) {
                        String amountStr = trans.split("\"amount\":")[1].split(",")[0];
                        String type = trans.contains("\"type\":\"deposit\"") ? "deposit" : "withdraw";
                        transactionHistory.add(new Transaction(type, Float.parseFloat(amountStr)));
                    }
                }
            } catch (Exception e) {
                transactionHistory = new ArrayList<>();
            }
        }
    }
    
    private void updateBalanceDisplay() {
        float currentBalance = sharedPreferences.getFloat(BALANCE_KEY, 0.0f);
        balanceTextView.setText(String.format("$%.2f", currentBalance));
    }
    
    private void setupClickListeners() {
        depositButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processTransaction("deposit", 100.0f);
            }
        });
        
        withdrawButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                processTransaction("withdraw", 50.0f);
            }
        });
        
        viewHistoryButton.setOnClickListener(new View.OnClickListener() {
            @Override
            public void onClick(View v) {
                showTransactionHistory();
            }
        });
    }
    
    private void processTransaction(String type, float amount) {
        float currentBalance = sharedPreferences.getFloat(BALANCE_KEY, 0.0f);
        float newBalance = type.equals("deposit") ? currentBalance + amount : currentBalance - amount;
        
        if (newBalance < 0) {
            Toast.makeText(this, "Insufficient funds", Toast.LENGTH_SHORT).show();
            return;
        }
        
        SharedPreferences.Editor editor = sharedPreferences.edit();
        editor.putFloat(BALANCE_KEY, newBalance);
        editor.apply();
        
        // Add to transaction history
        transactionHistory.add(new Transaction(type, amount));
        saveTransactionHistory();
        
        updateBalanceDisplay();
        Toast.makeText(this, type + " successful", Toast.LENGTH_SHORT).show();
    }
    
    private void saveTransactionHistory() {
        StringBuilder historyJson = new StringBuilder("[");
        for (int i = 0; i < transactionHistory.size(); i++) {
            Transaction trans = transactionHistory.get(i);
            historyJson.append("{\"type\":\"").append(trans.type)
                      .append("\",\"amount\":").append(trans.amount).append("}");
            if (i < transactionHistory.size() - 1) {
                historyJson.append(",");
            }
        }
        historyJson.append("]");
        
        SharedPreferences.Editor editor = sharedPreferences.edit();
        editor.putString(TRANSACTION_HISTORY_KEY, historyJson.toString());
        editor.apply();
    }
    
    private void showTransactionHistory() {
        StringBuilder history = new StringBuilder("Transaction History:\n");
        for (Transaction trans : transactionHistory) {
            history.append(trans.type).append(": $").append(trans.amount).append("\n");
        }
        Toast.makeText(this, history.toString(), Toast.LENGTH_LONG).show();
    }
    
    private class Transaction {
        String type;
        float amount;
        
        Transaction(String type, float amount) {
            this.type = type;
            this.amount = amount;
        }
    }
}